<template>
    <div>
        <div class="blogPage">
            <!-- 使用 mavon-editor 组件展示 Markdown 内容 -->
            <mavon-editor style="position:static" :value="markdownContent" :editable="false" :subfield="false"
                :defaultOpen="'preview'" :toolbarsFlag="false" :scrollStyle="true" :ishljs="true" />
        </div>
    </div>
</template>
  
<script>
import axios from 'axios';
import 'mavon-editor/dist/css/index.css';
import { mavonEditor } from 'mavon-editor';
export default {
    components: {
        mavonEditor
    },
    data() {
        return {
            markdownID: null,// 初始化为null
            markdownContent: ''
        };
    },
    created() {
        // 在组件创建时获取路由参数中的id，并赋值给markdownID
        this.markdownID = this.$route.query.id;
    },
    methods: {

    },
    mounted() {
        axios.get("https://120.79.72.63/getDoc/" + this.markdownID)
            .then(resp => {
                this.markdownContent = resp.data.data[0].docMain; //响应数据赋值给数据模型
                this.markdownContent = this.markdownContent.replace(/!\[.*?\]\((.*?)\)|<img src="(.*?)"(.*?)>/g, (match, p1, p2, p3) => {
                    console.log("匹配成功")
                    if (p1) {
                        return `<img src='http://gitee.com/lysssyo/WXMiniProgramPic/raw/main/${p1}'/>`;
                    } else {
                        return `<img src='http://gitee.com/lysssyo/WXMiniProgramPic/raw/main/${p2}' ${p3}>`;
                    }
                });
                console.log(this.markdownContent);
            });

    }
};
</script>
  